    int n,
    int num_log,
    int num_phy,
    long long *out_phy2log,
    long long *out_rank,
    long long *out_logcnt
) {
    double *effective = (double*)malloc(num_log * sizeof(double));

    for (int row = 0; row < n; row++) {
        const double *w = weight + row * num_log;
        long long *p2l = out_phy2log + row * num_phy;
        long long *rk = out_rank + row * num_phy;
        long long *lc = out_logcnt + row * num_log;

        /* Initialize: first num_log physical experts map 1:1 */
        for (int i = 0; i < num_log; i++) {
            p2l[i] = i;
            rk[i] = 0;
            lc[i] = 1;
            effective[i] = w[i];  /* w[i] / 1 */
        }
        for (int i = num_log; i < num_phy; i++) {
            p2l[i] = 0;
            rk[i] = 0;
        }

        /* Greedily assign redundant slots */
        for (int i = num_log; i < num_phy; i++) {
            /* Find expert with max effective load (weight / count) */
            int best = 0;
            double best_val = effective[0];
            for (int j = 1; j < num_log; j++) {
                if (effective[j] > best_val) {
                    best_val = effective[j];
                    best = j;
                }
            }
            p2l[i] = best;
            rk[i] = lc[best];
            lc[best]++;
            effective[best] = w[best] / (double)lc[best];
        }
    }

    free(effective);
}
"""

def _compile_c_lib():
    """Compile the C extension and return the ctypes library."""
    cache_dir = pathlib.Path(tempfile.gettempdir()) / "eplb_cache"
    cache_dir.mkdir(exist_ok=True)
    lib_path = cache_dir / "eplb_fast.so"
    src_path = cache_dir / "eplb_fast.c"

    # Only recompile if needed
    if not lib_path.exists():
        src_path.write_text(_C_SOURCE)
        subprocess.run(
            ["gcc", "-O3", "-march=native", "-shared", "-fPIC", "-o", str(lib_path), str(src_path)],
            check=True, capture_output=True
        )

    return ctypes.CDLL(str(lib_path))


_lib = _compile_c_lib()

# Set up function signatures
_lib.balanced_packing.restype = None
_lib.balanced_packing.argtypes = [
    ctypes.POINTER(ctypes.c_double),  # weight
    ctypes.c_int,                      # num_layers
    ctypes.c_int,                      # num_groups
    ctypes.c_int,                      # num_packs
    ctypes.POINTER(ctypes.c_longlong), # out_pack_index
    ctypes.POINTER(ctypes.c_longlong), # out_rank_in_pack
]

_lib.replicate_experts.restype = None
_lib.replicate_experts.argtypes = [
    ctypes.POINTER(ctypes.c_double),   # weight
    ctypes.c_int,                       # n
    ctypes.c_int,                       # num_log
    ctypes.c_int,                       # num_phy
    ctypes.POINTER(ctypes.c_longlong),  # out_phy2log
    ctypes.POINTER(ctypes.c_longlong),  # out_rank
    ctypes.POINTER(ctypes.c_longlong),  # out_logcnt
]


def balanced_packing(weight: torch.Tensor,
                     num_packs: int) -> tuple[torch.Tensor, torch.Tensor]:
    num_layers, num_groups = weight.shape
    assert num_groups % num_packs == 0

    if num_groups // num_packs == 1:
        pack_index = torch.arange(num_groups, dtype=torch.int64).expand(num_layers, -1)
        rank_in_pack = torch.zeros(num_layers, num_groups, dtype=torch.int64)
        return pack_index, rank_in_pack

    # Convert to contiguous numpy
    w_np = weight.numpy().astype(np.float64)
    if not w_np.flags['C_CONTIGUOUS']:
        w_np = np.ascontiguousarray(w_np)

    pack_index_np = np.empty((num_layers, num_groups), dtype=np.int64)
    rank_in_pack_np = np.empty((num_layers, num_groups), dtype=np.int64)

    _lib.balanced_packing(
        w_np.ctypes.data_as(ctypes.POINTER(ctypes.c_double)),
        ctypes.c_int(num_layers),
        ctypes.c_int(num_groups),
        ctypes.c_int(num_packs),
        pack_index_np.ctypes.data_as(ctypes.POINTER(ctypes.c_longlong)),
        rank_in_pack_np.ctypes.data_as(ctypes.POINTER(ctypes.c_longlong)),
    )

    return torch.from_numpy(pack_index_np), torch.from_numpy(rank_in_pack_np)


def replicate_experts(
        weight: torch.Tensor,
        num_phy: int) -> tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
    n, num_log = weight.shape
    num_redundant = num_phy - num_log
    assert num_redundant >= 0

    w_np = weight.numpy().astype(np.float64)
    if not w_np.flags['C_CONTIGUOUS']:
        w_np = np.ascontiguousarray(w_np)

    phy2log_np = np.empty((n, num_phy), dtype=np.int64)
    rank_np = np.empty((n, num_phy), dtype=np.int64)
    logcnt_np = np.empty((n, num_log), dtype=np.int64)

    _lib.replicate_experts(
        w_np.ctypes.data_as(ctypes.POINTER(ctypes.c_double)),
        ctypes.c_int(n),
        ctypes.c_int(num_log),
        ctypes.c_int(num_phy),
        phy2log_np.ctypes.data_as(ctypes.POINTER(ctypes.c_longlong)),
        rank_np.ctypes.data_as(ctypes.POINTER(ctypes.c_longlong)),
        logcnt_np.ctypes.data_as(ctypes.POINTER(ctypes.c_longlong)),
    )

    return torch.from_numpy(phy2log_np), torch.from_numpy(rank_np), torch.from_numpy(logcnt_np)


def rebalance_experts_hierarchical(
    weight: torch.Tensor,
    num_physical_experts: int,
    num_groups: int,
    num_nodes: int,
    num_gpus: int,
):
    num_layers, num_logical_experts = weight.shape
    group_size = num_logical_experts // num_groups
    groups_per_node = num_groups // num_nodes
    phy_experts_per_gpu = num_physical_experts // num_gpus

    def inverse(perm: torch.Tensor) -> torch.Tensor:
        inv = torch.empty_like(perm)
        inv.scatter_(
            1, perm,
            torch.arange(perm.size(1), dtype=torch.int64).expand(perm.shape),
        )
        return inv

    # Step 1: pack groups to nodes
    tokens_per_group = weight.unflatten(-1, (num_groups, group_size)).sum(-1)
    group_pack_index, group_rank_in_pack = balanced_packing(tokens_per_group, num_nodes)
    log2mlog = (((group_pack_index * groups_per_node + group_rank_in_pack) *
                 group_size).unsqueeze(-1) +
                torch.arange(group_size, dtype=torch.int64)).flatten(-2)
    mlog2log = inverse(log2mlog)

    # Step 2: construct redundant experts within nodes
    tokens_per_mlog = weight.gather(-1, mlog2log).view(-1, num_logical_experts // num_nodes)
    phy2mlog, phyrank, mlogcnt = replicate_experts(
        tokens_per_mlog, num_physical_experts // num_nodes)

    # Step 3: pack physical experts to GPUs
    tokens_per_phy = (tokens_per_mlog / mlogcnt).gather(-1, phy2mlog)
    pack_index, rank_in_pack = balanced_packing(tokens_per_phy, num_gpus // num_nodes)
    phy2pphy = pack_index * phy_experts_per_gpu + rank_in_pack
    pphy2phy = inverse(phy2pphy)

    pphy2mlog = phy2mlog.gather(-1, pphy2phy)
    pphy2mlog = (pphy2mlog.view(num_layers, num_nodes, -1) + torch.arange(
        0, num_logical_experts, num_logical_experts // num_nodes,
        dtype=torch.int64).view(1, -1, 1)).flatten(-2)
    pphy2log = mlog2log.gather(-1, pphy2mlog)
    pphyrank = phyrank.gather(-1, pphy2phy).view(num_layers, -1)
    logcnt = mlogcnt.view(num_layers, -1).gather(-1, log2mlog)
    return pphy2log, pphyrank, logcnt


def rebalance_experts(
    weight: torch.Tensor,
    num_replicas: int,
    num_groups: int,
    num_nodes: int,
    num_gpus: int,
) -> tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
    num_layers, num_logical_experts = weight.shape
    weight = weight.float().cpu()
    if num_groups % num_nodes == 0:
        phy2log, phyrank, logcnt = rebalance_experts_hierarchical(
            weight, num_replicas, num_groups, num_nodes, num_gpus)
    else:
        phy2log, phyrank, logcnt = rebalance_experts_hierarchical(
            weight, num_replicas, 1, 1, num_gpus)
    num_redundant_experts = num_replicas - num_logical_experts
    maxlogcnt = num_redundant_experts + 1
    log2phy: torch.Tensor = torch.full(
        (num_layers, num_logical_experts, maxlogcnt),
        -1,
        dtype=torch.int64,
    )
    log2phy.view(num_layers, -1).scatter_(
        -1,
        phy2log * maxlogcnt + phyrank,
        torch.arange(num_replicas, dtype=torch.int64).expand(num_layers, -1),
    )
    return phy2log, log2phy, logcnt


# EVOLVE-BLOCK-END

__all__ = ["rebalance_experts"]

