# SPDX-License-Identifier: Apache-2.0
"""
Expert parallelism load balancer (EPLB) for vLLM.

This module implements the core rearrangement algorithm using compiled C for
inner loops and numpy for all array operations (avoiding torch CPU overhead).
"""

# EVOLVE-BLOCK-START

import torch
import numpy as np
import ctypes
import subprocess
import os
import pathlib
import hashlib

# Compile C extension at module load time
_C_SOURCE = r"""
#include <stdlib.h>
#include <string.h>
#include <float.h>

void balanced_packing(
    const float *weight,
    int num_layers,
    int num_groups,
    int num_packs,
    long long *out_pack_index,
    long long *out_rank_in_pack
) {
    int groups_per_pack = num_groups / num_packs;
    int *indices = (int*)malloc(num_groups * sizeof(int));
    double *pack_weights = (double*)malloc(num_packs * sizeof(double));
    int *pack_items = (int*)malloc(num_packs * sizeof(int));

    for (int layer = 0; layer < num_layers; layer++) {
        const float *w = weight + layer * num_groups;
        long long *pi = out_pack_index + layer * num_groups;
        long long *rp = out_rank_in_pack + layer * num_groups;

        /* Sort indices by weight descending (stable insertion sort) */
        for (int i = 0; i < num_groups; i++) indices[i] = i;
        for (int i = 1; i < num_groups; i++) {
            int key = indices[i];
            float key_w = w[key];
            int j = i - 1;
            while (j >= 0 && w[indices[j]] < key_w) {
                indices[j + 1] = indices[j];
                j--;
            }
            indices[j + 1] = key;
        }

        memset(pack_weights, 0, num_packs * sizeof(double));
        memset(pack_items, 0, num_packs * sizeof(int));

        for (int idx = 0; idx < num_groups; idx++) {
            int group = indices[idx];
            int best_pack = -1;
            double best_weight = DBL_MAX;
            for (int p = 0; p < num_packs; p++) {
                if (pack_items[p] < groups_per_pack && pack_weights[p] < best_weight) {
                    best_weight = pack_weights[p];
                    best_pack = p;
                }
            }
            pi[group] = best_pack;
            rp[group] = pack_items[best_pack];
            pack_weights[best_pack] += (double)w[group];
            pack_items[best_pack]++;
        }
    }

    free(indices);
    free(pack_weights);
    free(pack_items);
}

void replicate_experts(
    const float *weight,
    int n,
    int num_log,
    int num_phy,
    long long *out_phy2log,
    long long *out_rank,
    long long *out_logcnt
) {
    double *effective = (double*)malloc(num_log * sizeof(double));

    for (int row = 0; row < n; row++) {
        const float *w = weight + row * num_log;
        long long *p2l = out_phy2log + row * num_phy;
        long long *rk = out_rank + row * num_phy;
        long long *lc = out_logcnt + row * num_log;

        for (int i = 0; i < num_log; i++) {
            p2l[i] = i;
            rk[i] = 0;
            lc[i] = 1;
            effective[i] = (double)w[i];
        }

        for (int i = num_log; i < num_phy; i++) {
            int best = 0;
            double best_val = effective[0];
            for (int j = 1; j < num_log; j++) {
                if (effective[j] > best_val) {
                    best_val = effective[j];
                    best = j;
                }
            }
            p2l[i] = best;
            rk[i] = lc[best];
            lc[best]++;
            effective[best] = (double)w[best] / (double)lc[best];
        }
    }

    free(effective);
}
"""

def _compile_c_lib():
    """Compile the C extension and return the ctypes library."""
    cache_dir = pathlib.Path("/tmp/eplb_cache")
    cache_dir.mkdir(exist_ok=True)
    src_hash = hashlib.md5(_C_SOURCE.encode()).hexdigest()[:8]
    lib_path = cache_dir / f"eplb_{src_hash}.so"
    src_path = cache_dir / f"eplb_{src_hash}.c"

    if not lib_path.exists():
        src_path.write_text(_C_SOURCE)
        subprocess.run(
            ["gcc", "-O3", "-march=native", "-shared", "-fPIC",
             "-o", str(lib_path), str(src_path)],
            check=True, capture_output=True
        )

    return ctypes.CDLL(str(lib_path))


_lib = _compile_c_lib()

_lib.balanced_packing.restype = None
_lib.balanced_packing.argtypes = [
    ctypes.POINTER(ctypes.c_float),
    ctypes.c_int, ctypes.c_int, ctypes.c_int,
    ctypes.POINTER(ctypes.c_longlong),
    ctypes.POINTER(ctypes.c_longlong),
]

_lib.replicate_experts.restype = None
_lib.replicate_experts.argtypes = [
    ctypes.POINTER(ctypes.c_float),
    ctypes.c_int, ctypes.c_int, ctypes.c_int,
    ctypes.POINTER(ctypes.c_longlong),
    ctypes.POINTER(ctypes.c_longlong),
    ctypes.POINTER(ctypes.c_longlong),
]


def _c_balanced_packing(weight_f32, num_packs):
    """weight_f32: numpy float32 array [layers, groups]"""
    num_layers, num_groups = weight_f32.shape
    groups_per_pack = num_groups // num_packs
    if groups_per_pack == 1:
        pi = np.tile(np.arange(num_groups, dtype=np.int64), (num_layers, 1))
        rp = np.zeros((num_layers, num_groups), dtype=np.int64)
        return pi, rp

    w = np.ascontiguousarray(weight_f32, dtype=np.float32)
    pi = np.empty((num_layers, num_groups), dtype=np.int64)
    rp = np.empty((num_layers, num_groups), dtype=np.int64)

    _lib.balanced_packing(
        w.ctypes.data_as(ctypes.POINTER(ctypes.c_float)),
        num_layers, num_groups, num_packs,
        pi.ctypes.data_as(ctypes.POINTER(ctypes.c_longlong)),
        rp.ctypes.data_as(ctypes.POINTER(ctypes.c_longlong)),
    )
    return pi, rp


def _c_replicate_experts(weight_f32, num_phy):
    """weight_f32: numpy float32 array [n, num_log]"""
    n, num_log = weight_f32.shape
    w = np.ascontiguousarray(weight_f32, dtype=np.float32)
    p2l = np.empty((n, num_phy), dtype=np.int64)
    rk = np.empty((n, num_phy), dtype=np.int64)
    lc = np.empty((n, num_log), dtype=np.int64)

    _lib.replicate_experts(
        w.ctypes.data_as(ctypes.POINTER(ctypes.c_float)),
        n, num_log, num_phy,
        p2l.ctypes.data_as(ctypes.POINTER(ctypes.c_longlong)),
        rk.ctypes.data_as(ctypes.POINTER(ctypes.c_longlong)),
        lc.ctypes.data_as(ctypes.POINTER(ctypes.c_longlong)),
    )
    return p2l, rk, lc


def _np_inverse(perm):
    """Inverse permutation for [layers, N] int64 array."""
    num_layers, N = perm.shape
    inv = np.empty_like(perm)
    rows = np.arange(num_layers)[:, None]
    inv[rows, perm] = np.arange(N, dtype=np.int64)[None, :]
    return inv


def _np_gather(source, indices):
    """Equivalent to torch gather dim=-1: out[i,j] = source[i, indices[i,j]]"""
    rows = np.arange(source.shape[0])[:, None]
    return source[rows, indices]


def rebalance_experts(
    weight: torch.Tensor,
    num_replicas: int,
    num_groups: int,
    num_nodes: int,
    num_gpus: int,
) -> tuple[torch.Tensor, torch.Tensor, torch.Tensor]:
    num_layers, num_logical_experts = weight.shape
    # Convert to numpy float32 once
    w_np = weight.float().cpu().numpy()

    if num_groups % num_nodes == 0:
        phy2log, phyrank, logcnt = _hierarchical_np(
            w_np, num_replicas, num_groups, num_nodes, num_gpus)
    else:
        phy2log, phyrank, logcnt = _hierarchical_np(
            w_np, num_replicas, 1, 1, num_gpus)

    num_redundant_experts = num_replicas - num_logical_experts
    maxlogcnt = num_redundant_experts + 1

    # Build log2phy mapping
    log2phy = np.full((num_layers, num_logical_experts * maxlogcnt), -1, dtype=np.int64)
    scatter_indices = phy2log * maxlogcnt + phyrank
    replicas_range = np.arange(num_replicas, dtype=np.int64)[None, :]
    rows = np.arange(num_layers)[:, None]
    # Use advanced indexing to scatter
    np.put_along_axis(log2phy, scatter_indices, np.broadcast_to(replicas_range, (num_layers, num_replicas)), axis=1)
    log2phy = log2phy.reshape(num_layers, num_logical_experts, maxlogcnt)

    return (
        torch.from_numpy(phy2log),
        torch.from_numpy(log2phy),
        torch.from_numpy(logcnt),
    )


def _hierarchical_np(weight, num_physical_experts, num_groups, num_nodes, num_gpus):
    """All-numpy implementation of hierarchical rebalancing."""
    num_layers, num_logical_experts = weight.shape
    group_size = num_logical_experts // num_groups
    groups_per_node = num_groups // num_nodes
    phy_experts_per_gpu = num_physical_experts // num_gpus

    # Step 1: pack groups to nodes
    # tokens_per_group: [layers, num_groups]
    tokens_per_group = weight.reshape(num_layers, num_groups, group_size).sum(axis=-1)
    group_pack_index, group_rank_in_pack = _c_balanced_packing(tokens_per_group, num_nodes)

    # log2mlog: [layers, num_logical_experts]
    base = (group_pack_index * groups_per_node + group_rank_in_pack) * group_size
    # Expand by group_size
    log2mlog = (base[:, :, None] + np.arange(group_size, dtype=np.int64)[None, None, :]).reshape(num_layers, num_logical_experts)
    mlog2log = _np_inverse(log2mlog)

    # Step 2: replicate within nodes
    # Gather weight according to mlog2log permutation
    tokens_per_mlog = _np_gather(weight, mlog2log)
    experts_per_node = num_logical_experts // num_nodes
    phy_per_node = num_physical_experts // num_nodes
    tokens_per_mlog_flat = tokens_per_mlog.reshape(-1, experts_per_node)

    phy2mlog, phyrank, mlogcnt = _c_replicate_experts(
        tokens_per_mlog_flat.astype(np.float32), phy_per_node)

    # Step 3: pack physical experts to GPUs
    # tokens_per_phy: effective load per physical expert
    gpus_per_node = num_gpus // num_nodes
    tokens_per_mlog_flat_f = tokens_per_mlog_flat.astype(np.float32)
    mlogcnt_f = mlogcnt.astype(np.float32)
    eff_load = tokens_per_mlog_flat_f / mlogcnt_f
    tokens_per_phy = _np_gather(eff_load, phy2mlog).astype(np.float32)

    pack_index, rank_in_pack = _c_balanced_packing(tokens_per_phy, gpus_per_node)

    phy2pphy = pack_index * phy_experts_per_gpu + rank_in_pack
    pphy2phy = _np_inverse(phy2pphy)

    # Map back
    pphy2mlog = _np_gather(phy2mlog, pphy2phy)
    # Reshape to [layers, nodes, phy_per_node] and add node offsets
    pphy2mlog = pphy2mlog.reshape(num_layers, num_nodes, -1)
    node_offsets = np.arange(0, num_logical_experts, experts_per_node, dtype=np.int64).reshape(1, -1, 1)
    pphy2mlog = (pphy2mlog + node_offsets).reshape(num_layers, -1)

    pphy2log = _np_gather(mlog2log, pphy2mlog)
    pphyrank = _np_gather(phyrank, pphy2phy).reshape(num_layers, -1)
    logcnt = _np_gather(mlogcnt.reshape(num_layers, -1), log2mlog)

    return pphy2log, pphyrank, logcnt


# EVOLVE-BLOCK-END

__all__ = ["rebalance_experts"]

