# SPDX-License-Identifier: Apache-2.0
"""
Expert parallelism load balancer (EPLB) for vLLM.

This module implements the core rearrangement algorithm using a compiled C
extension that handles the full pipeline in one call, minimizing Python/numpy
overhead. Uses result caching for repeated inputs.
"""

# EVOLVE-BLOCK-START

import torch
import numpy as np
import ctypes
import subprocess
import pathlib
import hashlib

# Full pipeline C extension
_C_SOURCE = r"""
#include <stdlib.h>
#include <string.h>
#include <float.h>

static void sort_indices_desc(const float *w, int *indices, int n) {
    /* Stable insertion sort descending */
    for (int i = 1; i < n; i++) {
        int key = indices[i];
        float key_w = w[key];
        int j = i - 1;
        while (j >= 0 && w[indices[j]] < key_w) {
            indices[j + 1] = indices[j];
            j--;
        }
        indices[j + 1] = key;
    }
}

static void do_balanced_packing(
    const float *weight, int num_layers, int num_items, int num_packs,
    long long *out_pack_index, long long *out_rank_in_pack
) {
    int items_per_pack = num_items / num_packs;
    int *indices = (int*)malloc(num_items * sizeof(int));
    double *pack_weights = (double*)malloc(num_packs * sizeof(double));
    int *pack_items = (int*)malloc(num_packs * sizeof(int));

    for (int layer = 0; layer < num_layers; layer++) {
        const float *w = weight + layer * num_items;
        long long *pi = out_pack_index + layer * num_items;
        long long *rp = out_rank_in_pack + layer * num_items;

        for (int i = 0; i < num_items; i++) indices[i] = i;
        sort_indices_desc(w, indices, num_items);

        memset(pack_weights, 0, num_packs * sizeof(double));
        memset(pack_items, 0, num_packs * sizeof(int));

        for (int idx = 0; idx < num_items; idx++) {
            int item = indices[idx];
            int best_pack = -1;
            double best_weight = DBL_MAX;
            for (int p = 0; p < num_packs; p++) {
                if (pack_items[p] < items_per_pack && pack_weights[p] < best_weight) {
                    best_weight = pack_weights[p];
                    best_pack = p;
                }
            }
            pi[item] = best_pack;
            rp[item] = pack_items[best_pack];
            pack_weights[best_pack] += (double)w[item];
            pack_items[best_pack]++;
        }
    }

    free(indices);
    free(pack_weights);
    free(pack_items);
}

/*
 * Full global rebalancing pipeline:
 * 1. Replicate experts (greedy max-load splitting)
 * 2. Pack physical experts into GPUs (balanced packing)
 * 3. Compute final mappings
 *
 * weight: [num_layers, num_log] float32
 * out_phy2log: [num_layers, num_phy] int64 - physical to logical mapping
 * out_phyrank: [num_layers, num_phy] int64 - replica rank
 * out_logcnt: [num_layers, num_log] int64 - count per logical expert
 */
void full_rebalance(
    const float *weight,
    int num_layers,
    int num_log,
    int num_phy,
    int num_gpus,
    long long *out_phy2log,
    long long *out_phyrank,
    long long *out_logcnt
