    double *effective = (double*)malloc(num_log * sizeof(double));
    float *tokens_per_phy = (float*)malloc(num_layers * num_phy * sizeof(float));
    long long *pack_index = (long long*)malloc(num_layers * num_phy * sizeof(long long));
    long long *rank_in_pack = (long long*)malloc(num_layers * num_phy * sizeof(long long));
    long long *phy2pphy = (long long*)malloc(num_layers * num_phy * sizeof(long long));
    long long *pphy2phy = (long long*)malloc(num_layers * num_phy * sizeof(long long));

    /* Step 1: Replicate experts */
    for (int layer = 0; layer < num_layers; layer++) {
        const float *w = weight + layer * num_log;
